from flask import Flask, request, redirect, url_for, session
import os
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Mock database for demonstration purposes
users_db = {
    "user1@example.com": {"mfa_enabled": False}
}

def send_email(to_email, subject, body):
    msg = MIMEText(body)
    msg['From'] = 'your-email@example.com'
    msg['To'] = to_email
    msg['Subject'] = subject
    with smtplib.SMTP('smtp.example.com', 587) as server:
        server.starttls()
        server.login('your-email@example.com', 'your-password')
        server.sendmail('your-email@example.com', to_email, msg.as_string())

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    email = request.form['email']
    if email in users_db:
        users_db[email]['mfa_enabled'] = True
        return "MFA enabled successfully"
    else:
        return "User not found", 404

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    email = request.form['email']
    if email in users_db:
        users_db[email]['mfa_enabled'] = False
        return "MFA disabled successfully"
    else:
        return "User not found", 404

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    email = request.form['email']
    if email in users_db:
        reset_link = url_for('disable_mfa', _external=True) + f"?email={email}"
        send_email(email, "MFA Reset Link", f"Click the link to reset MFA: {reset_link}")
        return "Reset link sent successfully"
    else:
        return "User not found", 404

@app.route('/disable-mfa/<email>', methods=['GET'])
def disable_mfa_with_link(email):
    if email in users_db:
        users_db[email]['mfa_enabled'] = False
        session['logged_in'] = True
        return "MFA disabled. Please log in with your password."
    else:
        return "User not found", 404

if __name__ == '__main__':
    app.run(debug=True)